#[repr(C)]
#[derive(AlignedBorrow, Debug)]
pub struct GkrInputCols<T> {
    /// Whether the current row is enabled (i.e. not padding)
    pub is_enabled: T,

    pub proof_idx: T,

    pub n_logup: T,
    pub n_max: T,

    /// Flag indicating whether there are any interactions
    /// n_logup = 0 <=> total_interactions = 0
    pub is_n_logup_zero: T,
    pub is_n_logup_zero_aux: IsZeroAuxCols<T>,

    pub is_n_max_greater_than_n_logup: T,

    /// Transcript index
    pub tidx: T,

    /// Root denominator claim
    pub q0_claim: [T; D_EF],

    pub alpha_logup: [T; D_EF],

    pub input_layer_claim: [[T; D_EF]; 2],

    // Grinding
    pub logup_pow_witness: T,
    pub logup_pow_sample: T,
}

///////////////////////////////////////////////////////////////////////
// Boolean Constraints
///////////////////////////////////////////////////////////////////////

builder.assert_bool(local.is_n_max_greater_than_n_logup);

///////////////////////////////////////////////////////////////////////
// Proof Index Constraints
///////////////////////////////////////////////////////////////////////

// This subair has the following constraints:
// 1. Boolean enabled flag
// 2. Disabled rows are followed by disabled rows
// 3. Proof index increments by exactly one between enabled rows
ProofIdxSubAir.eval(
    builder,
    (
        ProofIdxIoCols {
            is_enabled: local.is_enabled,
            proof_idx: local.proof_idx,
        }
        .map_into(),
        ProofIdxIoCols {
            is_enabled: next.is_enabled,
            proof_idx: next.proof_idx,
        }
        .map_into(),
    ),
);

///////////////////////////////////////////////////////////////////////
// Base Constraints
///////////////////////////////////////////////////////////////////////

// 1. Check if n_logup is zero (no logup constraints needed)
IsZeroSubAir.eval(
    builder,
    (
        IsZeroIo::new(
            local.n_logup.into(),
            local.is_n_logup_zero.into(),
            local.is_enabled.into(),
        ),
        local.is_n_logup_zero_aux.inv,
    ),
);

///////////////////////////////////////////////////////////////////////
// Output Constraints
///////////////////////////////////////////////////////////////////////

let has_interactions = AB::Expr::ONE - local.is_n_logup_zero;
// Input layer claim is [0, \alpha] when no interactions
assert_zeros(
    &mut builder.when(not::<AB::Expr>(has_interactions.clone())),
    local.input_layer_claim[0],
);
assert_array_eq(
    &mut builder.when(not::<AB::Expr>(has_interactions.clone())),
    local.input_layer_claim[1],
    local.alpha_logup,
);

///////////////////////////////////////////////////////////////////////
// Module Interactions
///////////////////////////////////////////////////////////////////////

let num_layers = local.n_logup + AB::Expr::from_usize(self.l_skip);

let needs_challenges = or(local.is_n_max_greater_than_n_logup, local.is_n_logup_zero);
let num_challenges = local.n_max + AB::Expr::from_usize(self.l_skip)
    - has_interactions.clone() * num_layers.clone();

// Add PoW (if any) and alpha, beta
let logup_pow_offset = pow_tidx_count(self.logup_pow_bits);
let tidx_after_pow_and_alpha_beta =
    local.tidx + AB::Expr::from_usize(logup_pow_offset + 2 * D_EF);
// Add GKR layers + Sumcheck
let tidx_after_gkr_layers = tidx_after_pow_and_alpha_beta.clone()
    + has_interactions.clone()
        * num_layers.clone()
        * (num_layers.clone() + AB::Expr::TWO)
        * AB::Expr::from_usize(2 * D_EF);
// Add separately sampled challenges
let tidx_end = tidx_after_gkr_layers.clone()
    + needs_challenges.clone() * num_challenges.clone() * AB::Expr::from_usize(D_EF);

// 1. GkrLayerInputBus
// 1a. Send input to GkrLayerAir
self.layer_input_bus.send(
    builder,
    local.proof_idx,
    GkrLayerInputMessage {
        // Skip q0_claim
        tidx: (tidx_after_pow_and_alpha_beta + AB::Expr::from_usize(D_EF))
            * has_interactions.clone(),
        q0_claim: local.q0_claim.map(Into::into),
    },
    local.is_enabled * has_interactions.clone(),
);
// 2. GkrLayerOutputBus
// 2a. Receive input layer claim from GkrLayerAir
self.layer_output_bus.receive(
    builder,
    local.proof_idx,
    GkrLayerOutputMessage {
        tidx: tidx_after_gkr_layers.clone(),
        layer_idx_end: num_layers.clone() - AB::Expr::ONE,
        input_layer_claim: local.input_layer_claim.map(|claim| claim.map(Into::into)),
    },
    local.is_enabled * has_interactions.clone(),
);
// 3. GkrXiSamplerBus
// 3a. Send input to GkrXiSamplerAir
self.xi_sampler_bus.send(
    builder,
    local.proof_idx,
    GkrXiSamplerMessage {
        idx: has_interactions.clone() * num_layers,
        tidx: tidx_after_gkr_layers,
    },
    local.is_enabled * needs_challenges.clone(),
);
// 3b. Receive output from GkrXiSamplerAir
self.xi_sampler_bus.receive(
    builder,
    local.proof_idx,
    GkrXiSamplerMessage {
        idx: local.n_max + AB::Expr::from_usize(self.l_skip - 1),
        tidx: tidx_end.clone(),
    },
    local.is_enabled * needs_challenges,
);

///////////////////////////////////////////////////////////////////////
// External Interactions
///////////////////////////////////////////////////////////////////////

// 1. GkrModuleBus
// 1a. Receive initial GKR module message on first layer
self.gkr_module_bus.receive(
    builder,
    local.proof_idx,
    GkrModuleMessage {
        tidx: local.tidx,
        n_logup: local.n_logup,
        n_max: local.n_max,
        is_n_max_greater: local.is_n_max_greater_than_n_logup,
    },
    local.is_enabled,
);

// 2. TranscriptBus
if self.logup_pow_bits > 0 {
    // 2a. Observe pow witness
    self.transcript_bus.observe(
        builder,
        local.proof_idx,
        local.tidx.into(),
        local.logup_pow_witness.into(),
        local.is_enabled,
    );
    // 2b. Sample pow challenge
    self.transcript_bus.sample(
        builder,
        local.proof_idx,
        local.tidx.into() + AB::Expr::ONE,
        local.logup_pow_sample.into(),
        local.is_enabled,
    );
}

// 2c. Sample alpha_logup challenge
self.transcript_bus.sample_ext(
    builder,
    local.proof_idx,
    local.tidx.into() + AB::Expr::from_usize(logup_pow_offset),
    local.alpha_logup.map(Into::into),
    local.is_enabled,
);

// 2d. Observe `q0_claim` claim
self.transcript_bus.observe_ext(
    builder,
    local.proof_idx,
    local.tidx + AB::Expr::from_usize(logup_pow_offset + 2 * D_EF),
    local.q0_claim,
    local.is_enabled * has_interactions,
);

// 3. BatchConstraintModuleBus
// 3a. Send input layer claims for further verification
self.bc_module_bus.send(
    builder,
    local.proof_idx,
    BatchConstraintModuleMessage {
        tidx: tidx_end.clone() + AB::Expr::from_usize(D_EF),
        gkr_input_layer_claim: [
            local.input_layer_claim[0].map(Into::into),
            ext_field_subtract(local.input_layer_claim[1], local.alpha_logup),
        ],
    },
    local.is_enabled,
);

self.constraints_folding_input_bus.send(
    builder,
    local.proof_idx,
    ConstraintsFoldingInputMessage { tidx: tidx_end },
    local.is_enabled,
);
self.interactions_folding_input_bus.send(
    builder,
    local.proof_idx,
    InteractionsFoldingInputMessage {
        tidx: local.tidx + AB::Expr::from_usize(logup_pow_offset + D_EF), // skip alpha
    },
    local.is_enabled,
);

// 4. ExpBitsLenBus
// 4a. Check proof-of-work using `ExpBitsLenBus`.
if self.logup_pow_bits > 0 {
    self.exp_bits_len_bus.lookup_key(
        builder,
        ExpBitsLenMessage {
            base: AB::Expr::from_prime_subfield(
                <AB::Expr as PrimeCharacteristicRing>::PrimeSubfield::GENERATOR,
            ),
            bit_src: local.logup_pow_sample.into(),
            num_bits: AB::Expr::from_usize(self.logup_pow_bits),
            result: AB::Expr::ONE,
        },
        local.is_enabled,
    );
}

#[repr(C)]
#[derive(AlignedBorrow, Debug)]
pub struct GkrLayerCols<T> {
    /// Whether the current row is enabled (i.e. not padding)
    pub is_enabled: T,
    pub proof_idx: T,
    pub is_first: T,

    /// An enabled row which is not involved in any interactions
    /// but should satisfy air constraints
    pub is_dummy: T,

    /// GKR layer index
    pub layer_idx: T,

    /// Transcript index at the start of this layer
    pub tidx: T,

    /// Sampled batching challenge
    pub lambda: [T; D_EF],

    /// Layer claims
    pub p_xi_0: [T; D_EF],
    pub q_xi_0: [T; D_EF],
    pub p_xi_1: [T; D_EF],
    pub q_xi_1: [T; D_EF],

    // (p_xi_1 - p_xi_0) * mu + p_xi_0
    pub numer_claim: [T; D_EF],
    // (q_xi_1 - q_xi_0) * mu + q_xi_0
    pub denom_claim: [T; D_EF],

    // Sumcheck claim input
    pub sumcheck_claim_in: [T; D_EF],

    /// Received from GkrLayerSumcheckAir
    pub eq_at_r_prime: [T; D_EF],

    /// Corresponds to `mu` - reduction point
    pub mu: [T; D_EF],
}

///////////////////////////////////////////////////////////////////////
// Proof Index and Loop Constraints
///////////////////////////////////////////////////////////////////////

type LoopSubAir = NestedForLoopSubAir<1>;

// This subair has the following constraints:
// 1. Boolean enabled flag
// 2. Disabled rows are followed by disabled rows
// 3. Proof index increments by exactly one between enabled rows
LoopSubAir {}.eval(
    builder,
    (
        NestedForLoopIoCols {
            is_enabled: local.is_enabled,
            counter: [local.proof_idx],
            is_first: [local.is_first],
        }
        .map_into(),
        NestedForLoopIoCols {
            is_enabled: next.is_enabled,
            counter: [next.proof_idx],
            is_first: [next.is_first],
        }
        .map_into(),
    ),
);

let is_transition = LoopSubAir::local_is_transition(next.is_enabled, next.is_first);
let is_last = LoopSubAir::local_is_last(local.is_enabled, next.is_enabled, next.is_first);

// Layer index starts from 0
builder.when(local.is_first).assert_zero(local.layer_idx);
// Layer index increments by 1
builder
    .when(is_transition.clone())
    .assert_eq(next.layer_idx, local.layer_idx + AB::Expr::ONE);

///////////////////////////////////////////////////////////////////////
// Dummy Row Constraints
///////////////////////////////////////////////////////////////////////

// A proof can't contribute both dummy and non-dummy rows
builder
    .when(is_transition.clone())
    .assert_eq(next.is_dummy, local.is_dummy);
// Any proof segment with more than one layer row must be non-dummy
builder
    .when(is_transition.clone())
    .assert_zero(local.is_dummy);

// Dummy rows are only allowed as a singleton placeholder row
builder.when(local.is_dummy).assert_one(local.is_first);
builder.when(local.is_dummy).assert_one(is_last.clone());

///////////////////////////////////////////////////////////////////////
// Root Layer Constraints
///////////////////////////////////////////////////////////////////////

// Compute cross terms: p_cross = p_xi_0 * q_xi_1 + p_xi_1 * q_xi_0
//                       q_cross = q_xi_0 * q_xi_1
let (p_cross_term, q_cross_term) =
    compute_recursive_relations(local.p_xi_0, local.q_xi_0, local.p_xi_1, local.q_xi_1);

// Zero-check: verify p_cross = 0 at root layer
assert_zeros(&mut builder.when(local.is_first), p_cross_term.clone());

// Root consistency check: verify q_cross = q0_claim
assert_array_eq(
    &mut builder.when(local.is_first),
    q_cross_term.clone(),
    local.sumcheck_claim_in,
);

///////////////////////////////////////////////////////////////////////
// Layer Constraints
///////////////////////////////////////////////////////////////////////

// Reduce to single evaluation
// `numer_claim = (p_xi_1 - p_xi_0) * mu + p_xi_0`
// `denom_claim = (q_xi_1 - q_xi_0) * mu + q_xi_0`
let (numer_claim, denom_claim) = reduce_to_single_evaluation(
    local.p_xi_0,
    local.p_xi_1,
    local.q_xi_0,
    local.q_xi_1,
    local.mu,
);
assert_array_eq(builder, local.numer_claim, numer_claim);
assert_array_eq(builder, local.denom_claim, denom_claim);

///////////////////////////////////////////////////////////////////////
// Inter-Layer Constraints
///////////////////////////////////////////////////////////////////////

// Next layer claim is RLC of previous layer numer_claim and denom_claim
assert_array_eq(
    &mut builder.when(is_transition.clone()),
    next.sumcheck_claim_in,
    ext_field_add::<AB::Expr>(
        local.numer_claim,
        ext_field_multiply::<AB::Expr>(next.lambda, local.denom_claim),
    ),
);

// Transcript index increment
let tidx_after_sumcheck = local.tidx
    // Sample lambda on non-root layer
    + (AB::Expr::ONE - local.is_first) * AB::Expr::from_usize(D_EF)
    + local.layer_idx * AB::Expr::from_usize(4 * D_EF);
let tidx_end = tidx_after_sumcheck.clone() + AB::Expr::from_usize(5 * D_EF);
builder
    .when(is_transition.clone())
    .assert_eq(next.tidx, tidx_end.clone());

let is_not_dummy = AB::Expr::ONE - local.is_dummy;
let is_non_root_layer = local.is_enabled * (AB::Expr::ONE - local.is_first);

// 1. GkrLayerInputBus
// 1a. Receive GKR layers input
self.layer_input_bus.receive(
    builder,
    local.proof_idx,
    GkrLayerInputMessage {
        tidx: local.tidx,
        q0_claim: local.sumcheck_claim_in,
    },
    local.is_first * is_not_dummy.clone(),
);
// 2. GkrLayerOutputBus
// 2a. Send GKR input layer claims back
self.layer_output_bus.send(
    builder,
    local.proof_idx,
    GkrLayerOutputMessage {
        tidx: tidx_end,
        layer_idx_end: local.layer_idx.into(),
        input_layer_claim: [
            local.numer_claim.map(Into::into),
            local.denom_claim.map(Into::into),
        ],
    },
    is_last.clone() * is_not_dummy.clone(),
);

// 3. GkrSumcheckInputBus
// 3a. Send claim to sumcheck
self.sumcheck_input_bus.send(
    builder,
    local.proof_idx,
    GkrSumcheckInputMessage {
        layer_idx: local.layer_idx.into(),
        is_last_layer: is_last.clone(),
        tidx: local.tidx + AB::Expr::from_usize(D_EF),
        claim: local.sumcheck_claim_in.map(Into::into),
    },
    is_non_root_layer.clone() * is_not_dummy.clone(),
);
// 3. GkrSumcheckOutputBus
// 3a. Receive sumcheck results
let sumcheck_claim_out = ext_field_multiply::<AB::Expr>(
    ext_field_add::<AB::Expr>(
        p_cross_term,
        ext_field_multiply::<AB::Expr>(local.lambda, q_cross_term),
    ),
    local.eq_at_r_prime,
);
self.sumcheck_output_bus.receive(
    builder,
    local.proof_idx,
    GkrSumcheckOutputMessage {
        layer_idx: local.layer_idx.into(),
        tidx: tidx_after_sumcheck.clone(),
        claim_out: sumcheck_claim_out.map(Into::into),
        eq_at_r_prime: local.eq_at_r_prime.map(Into::into),
    },
    is_non_root_layer.clone() * is_not_dummy.clone(),
);
// 4. GkrSumcheckChallengeBus
// 4a. Send challenge mu
self.sumcheck_challenge_bus.send(
    builder,
    local.proof_idx,
    GkrSumcheckChallengeMessage {
        layer_idx: local.layer_idx.into(),
        sumcheck_round: AB::Expr::ZERO,
        challenge: local.mu.map(Into::into),
    },
    is_transition.clone() * is_not_dummy.clone(),
);

///////////////////////////////////////////////////////////////////////
// External Interactions
///////////////////////////////////////////////////////////////////////

// 1. TranscriptBus
// 1a. Sample `lambda`
self.transcript_bus.sample_ext(
    builder,
    local.proof_idx,
    local.tidx,
    local.lambda,
    is_non_root_layer.clone() * is_not_dummy.clone(),
);
// 1b. Observe layer claims
let mut tidx = tidx_after_sumcheck;
for claim in [local.p_xi_0, local.q_xi_0, local.p_xi_1, local.q_xi_1].into_iter() {
    self.transcript_bus.observe_ext(
        builder,
        local.proof_idx,
        tidx.clone(),
        claim,
        local.is_enabled * is_not_dummy.clone(),
    );
    tidx += AB::Expr::from_usize(D_EF);
}
// 1c. Sample `mu`
self.transcript_bus.sample_ext(
    builder,
    local.proof_idx,
    tidx,
    local.mu,
    local.is_enabled * is_not_dummy.clone(),
);

// 2. XiRandomnessBus
// 2a. Send shared randomness
self.xi_randomness_bus.send(
    builder,
    local.proof_idx,
    XiRandomnessMessage {
        idx: AB::Expr::ZERO,
        xi: local.mu.map(Into::into),
    },
    is_last * is_not_dummy.clone(),
);

#[repr(C)]
#[derive(AlignedBorrow, Debug)]
pub struct GkrLayerSumcheckCols<T> {
    /// Whether the current row is enabled (i.e. not padding)
    pub is_enabled: T,
    pub proof_idx: T,
    pub layer_idx: T,
    pub is_proof_start: T,
    pub is_first_round: T,

    /// An enabled row which is not involved in any interactions
    /// but should satisfy air constraints
    pub is_dummy: T,

    pub is_last_layer: T,

    /// Sumcheck sub-round index within this layer_idx (0..layer_idx-1)
    // perf(ayush): can probably remove round if XiRandomnessMessage takes tidx instead
    pub round: T,

    /// Transcript index
    pub tidx: T,

    /// s(1) in extension field
    pub ev1: [T; D_EF],
    /// s(2) in extension field
    pub ev2: [T; D_EF],
    /// s(3) in extension field
    pub ev3: [T; D_EF],

    /// The claim coming into this sub-round (either from previous sub-round or initial)
    pub claim_in: [T; D_EF],
    /// The claim going out of this sub-round (result of cubic interpolation)
    pub claim_out: [T; D_EF],

    /// Component `round` of the original point ξ^{(j-1)}
    /// (corresponding to `gkr_r[round]`)
    pub prev_challenge: [T; D_EF],
    /// The sampled challenge for this sub-round (corresponds to `ri`)
    pub challenge: [T; D_EF],

    /// The eq value coming into this sub-round
    pub eq_in: [T; D_EF],
    /// The eq value going out (updated for this round)
    pub eq_out: [T; D_EF],
}

///////////////////////////////////////////////////////////////////////
// Proof Index and Loop Constraints
///////////////////////////////////////////////////////////////////////

type LoopSubAir = NestedForLoopSubAir<2>;
LoopSubAir {}.eval(
    builder,
    (
        NestedForLoopIoCols {
            is_enabled: local.is_enabled.into(),
            counter: [local.proof_idx.into(), local.layer_idx - AB::F::ONE],
            is_first: [local.is_proof_start.into(), local.is_first_round.into()],
        }
        .map_into(),
        NestedForLoopIoCols {
            is_enabled: next.is_enabled.into(),
            counter: [next.proof_idx.into(), next.layer_idx - AB::F::ONE],
            is_first: [next.is_proof_start.into(), next.is_first_round.into()],
        },
    ),
);

let is_transition_round =
    LoopSubAir::local_is_transition(next.is_enabled, next.is_first_round);
let is_last_round =
    LoopSubAir::local_is_last(local.is_enabled, next.is_enabled, next.is_first_round);
let is_transition_proof = next.is_enabled - next.is_proof_start;

// Sumcheck round flag starts at 0
builder.when(local.is_first_round).assert_zero(local.round);
// Sumcheck round flag increments by 1
builder
    .when(is_transition_round.clone())
    .assert_eq(next.round, local.round + AB::Expr::ONE);
// Sumcheck round flag end
builder
    .when(is_last_round.clone())
    .assert_eq(local.round, local.layer_idx - AB::Expr::ONE);

///////////////////////////////////////////////////////////////////////
// Round Constraints
///////////////////////////////////////////////////////////////////////

// Layer metadata must remain same
builder
    .when(is_transition_round.clone())
    .assert_eq(next.is_last_layer, local.is_last_layer);

// Eq initialization: eq_in = 1 at first round
assert_one_ext(&mut builder.when(local.is_first_round), local.eq_in);

// Eq update: incrementally compute eq *= (xi * ri + (1-xi) * (1-ri))
let eq_out: [AB::Expr; D_EF] =
    update_eq(local.eq_in, local.prev_challenge, local.challenge);
assert_array_eq(&mut builder.when(local.is_enabled), local.eq_out, eq_out);

// Eq propagation
assert_array_eq(
    &mut builder.when(is_transition_round.clone()),
    local.eq_out,
    next.eq_in,
);

// Compute s(0) = claim_in - s(1)
let ev0: [AB::Expr; D_EF] = ext_field_subtract(local.claim_in, local.ev1);

// Cubic interpolation: compute claim_out from polynomial evals at 0,1,2,3
let claim_out: [AB::Expr; D_EF] =
    interpolate_cubic_at_0123(ev0, local.ev1, local.ev2, local.ev3, local.challenge);
assert_array_eq(builder, local.claim_out, claim_out);

// Claim propagation
assert_array_eq(
    &mut builder.when(is_transition_round.clone()),
    local.claim_out,
    next.claim_in,
);

// Transcript index increment
builder.when(is_transition_round.clone()).assert_eq(
    next.tidx,
    local.tidx.into() + AB::Expr::from_usize(4 * D_EF),
);

let is_not_dummy = AB::Expr::ONE - local.is_dummy;

// 1. GkrSumcheckInputBus
// 1a. Receive initial sumcheck input on first round
self.sumcheck_input_bus.receive(
    builder,
    local.proof_idx,
    GkrSumcheckInputMessage {
        layer_idx: local.layer_idx,
        is_last_layer: local.is_last_layer,
        tidx: local.tidx,
        claim: local.claim_in,
    },
    local.is_first_round * is_not_dummy.clone(),
);
// 2. GkrSumcheckOutputBus
// 2a. Send output back to GkrLayerAir on final round
self.sumcheck_output_bus.send(
    builder,
    local.proof_idx,
    GkrSumcheckOutputMessage {
        layer_idx: local.layer_idx.into(),
        tidx: local.tidx.into() + AB::Expr::from_usize(4 * D_EF),
        claim_out: local.claim_out.map(Into::into),
        eq_at_r_prime: local.eq_out.map(Into::into),
    },
    is_last_round.clone() * is_not_dummy.clone(),
);

// 3. GkrSumcheckChallengeBus
// 3a. Receive challenge from previous GKR layer_idx sumcheck
self.sumcheck_challenge_bus.receive(
    builder,
    local.proof_idx,
    GkrSumcheckChallengeMessage {
        layer_idx: local.layer_idx - AB::Expr::ONE,
        sumcheck_round: local.round.into(),
        challenge: local.prev_challenge.map(Into::into),
    },
    local.is_enabled * is_not_dummy.clone(),
);
// 3b. Send challenge to next GKR layer_idx sumcheck for eq calculation
self.sumcheck_challenge_bus.send(
    builder,
    local.proof_idx,
    GkrSumcheckChallengeMessage {
        layer_idx: local.layer_idx.into(),
        sumcheck_round: local.round.into() + AB::Expr::ONE,
        challenge: local.challenge.map(Into::into),
    },
    local.is_enabled * (AB::Expr::ONE - local.is_last_layer) * is_not_dummy.clone(),
);

///////////////////////////////////////////////////////////////////////
// External Interactions
///////////////////////////////////////////////////////////////////////

// 1. TranscriptBus
// 1a. Observe evaluations
let mut tidx = local.tidx.into();
for eval in [local.ev1, local.ev2, local.ev3].into_iter() {
    self.transcript_bus.observe_ext(
        builder,
        local.proof_idx,
        tidx.clone(),
        eval,
        local.is_enabled * is_not_dummy.clone(),
    );
    tidx += AB::Expr::from_usize(D_EF);
}
// 1b. Sample challenge `ri`
self.transcript_bus.sample_ext(
    builder,
    local.proof_idx,
    tidx,
    local.challenge,
    local.is_enabled * is_not_dummy.clone(),
);

// 2. XiRandomnessBus
// 2a. Send last challenge
self.xi_randomness_bus.send(
    builder,
    local.proof_idx,
    XiRandomnessMessage {
        idx: local.round + AB::Expr::ONE,
        xi: local.challenge.map(Into::into),
    },
    local.is_enabled * local.is_last_layer * is_not_dummy.clone(),
);

#[repr(C)]
#[derive(AlignedBorrow, Debug)]
pub struct GkrXiSamplerCols<T> {
    /// Whether the current row is enabled (i.e. not padding)
    pub is_enabled: T,
    pub proof_idx: T,
    pub is_first_challenge: T,

    /// An enabled row which is not involved in any interactions
    /// but should satisfy air constraints
    pub is_dummy: T,

    /// Challenge index
    // perf(ayush): can probably remove idx if XiRandomnessMessage takes tidx instead
    pub idx: T,

    /// Sampled challenge
    pub xi: [T; D_EF],
    /// Transcript index
    pub tidx: T,
}

///////////////////////////////////////////////////////////////////////
// Proof Index and Loop Constraints
///////////////////////////////////////////////////////////////////////

type LoopSubAir = NestedForLoopSubAir<1>;
LoopSubAir {}.eval(
    builder,
    (
        NestedForLoopIoCols {
            is_enabled: local.is_enabled,
            counter: [local.proof_idx],
            is_first: [local.is_first_challenge],
        }
        .map_into(),
        NestedForLoopIoCols {
            is_enabled: next.is_enabled,
            counter: [next.proof_idx],
            is_first: [next.is_first_challenge],
        }
        .map_into(),
    ),
);

let is_transition_challenge =
    LoopSubAir::local_is_transition(next.is_enabled, next.is_first_challenge);
let is_last_challenge =
    LoopSubAir::local_is_last(local.is_enabled, next.is_enabled, next.is_first_challenge);

// Challenge index increments by 1
builder
    .when(is_transition_challenge.clone())
    .assert_eq(next.idx, local.idx + AB::Expr::ONE);

///////////////////////////////////////////////////////////////////////
// Dummy Row Constraints
///////////////////////////////////////////////////////////////////////

// A proof can't contribute both dummy and non-dummy rows
builder
    .when(is_transition_challenge.clone())
    .assert_eq(next.is_dummy, local.is_dummy);
// Any proof segment with more than one challenge row must be non-dummy
builder
    .when(is_transition_challenge.clone())
    .assert_zero(local.is_dummy);

// Dummy rows are only allowed as a singleton placeholder row
builder
    .when(local.is_dummy)
    .assert_one(local.is_first_challenge);
builder
    .when(local.is_dummy)
    .assert_one(is_last_challenge.clone());

///////////////////////////////////////////////////////////////////////
// Transition Constraints
///////////////////////////////////////////////////////////////////////

builder
    .when(is_transition_challenge.clone())
    .assert_eq(next.tidx, local.tidx + AB::Expr::from_usize(D_EF));

///////////////////////////////////////////////////////////////////////
// Module Interactions
///////////////////////////////////////////////////////////////////////

let is_not_dummy = AB::Expr::ONE - local.is_dummy;

// 1. GkrXiSamplerBus
// 1a. Receive input from GkrInputAir
self.xi_sampler_bus.receive(
    builder,
    local.proof_idx,
    GkrXiSamplerMessage {
        idx: local.idx.into(),
        tidx: local.tidx.into(),
    },
    local.is_first_challenge * is_not_dummy.clone(),
);
// 1b. Send output to GkrInputAir
let tidx_end = local.tidx + AB::Expr::from_usize(D_EF);
self.xi_sampler_bus.send(
    builder,
    local.proof_idx,
    GkrXiSamplerMessage {
        idx: local.idx.into(),
        tidx: tidx_end,
    },
    is_last_challenge.clone() * is_not_dummy.clone(),
);

///////////////////////////////////////////////////////////////////////
// External Interactions
///////////////////////////////////////////////////////////////////////

// 1. TranscriptBus
// 1a. Sample challenge from transcript
self.transcript_bus.sample_ext(
    builder,
    local.proof_idx,
    local.tidx,
    local.xi,
    local.is_enabled * is_not_dummy.clone(),
);

// 2. XiRandomnessBus
// 2a. Send shared randomness
self.xi_randomness_bus.send(
    builder,
    local.proof_idx,
    XiRandomnessMessage {
        idx: local.idx.into(),
        xi: local.xi.map(Into::into),
    },
    local.is_enabled * is_not_dummy,
);
